import json, os, re, time, hashlib, urllib.request, urllib.parse, boto3
ddb = boto3.client("dynamodb"); br = boto3.client("bedrock-runtime")
T = os.environ["AUDIT_TABLE"]; M = os.environ["MODEL_ID"]; G = os.environ.get("GUARDRAIL_ID", "")
SK = os.environ.get("SCORECARD_KEY", "DEMO_KEY")
SB = os.environ.get("SCORECARD_BASE", "https://api.data.gov/ed/collegescorecard/v1")
# Synthetic SIS pilot data (production points sis.status at the real SIS connector under FERPA sign-off).
SIS = {"S-100": {"aid_status": "awaiting verification", "balance_due": "$0.00"},
       "S-200": {"aid_status": "complete", "balance_due": "$150.00"}}
GRANTS = {"STUDENT": {"kb.search", "sis.status"},
          "COUNSELOR": {"kb.search", "sis.status", "comms.send"}}
CONSEQUENTIAL = {"comms.send"}
PATS = [(re.compile(r"\b\d{3}-\d{2}-\d{4}\b"), "[SSN-REDACTED]"),
        (re.compile(r"\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b"), "[EMAIL-REDACTED]"),
        (re.compile(r"\bS-\d+\b"), "[SID-REDACTED]")]
def mask(t):
    t = t or ""
    for p, r in PATS:
        t = p.sub(r, t)
    return t
def scorecard(q):
    params = {"school.name": q, "fields": "school.name,school.city,school.state,latest.cost.tuition.in_state,latest.admissions.admission_rate.overall", "per_page": 1, "api_key": SK}
    u = SB + "/schools?" + urllib.parse.urlencode(params)
    d = json.loads(urllib.request.urlopen(u, timeout=8).read())
    rs = d.get("results", [])
    return rs[0] if rs else {}
def audit(**k):
    aid = "AUD-" + hashlib.sha256((str(time.time()) + json.dumps(k, default=str)).encode()).hexdigest()[:20]
    item = {"audit_id": {"S": aid}, "ts": {"N": str(int(time.time()))}}
    for x, v in k.items():
        item[x] = {"S": str(v)[:400]}
    ddb.put_item(TableName=T, Item=item, ConditionExpression="attribute_not_exists(audit_id)")
    return aid
def handler(event, context):
    claims = event.get("claims") or {}
    role = claims.get("role", "STUDENT"); sub = claims.get("sub", "anon"); own = claims.get("student_id", "")
    tool = event.get("tool", "kb.search"); q = event.get("query", ""); target = event.get("student_id", own)
    if tool not in GRANTS.get(role, set()):
        return {"decision": "DENY", "reason": "not entitled", "audit_id": audit(decision="DENY", user=sub, tool=tool, reason="not entitled")}
    if tool == "sis.status" and role == "STUDENT" and target != own:
        return {"decision": "DENY", "reason": "record scope: own record only", "audit_id": audit(decision="DENY", user=sub, tool=tool, reason="record-scope")}
    if tool in CONSEQUENTIAL and not event.get("approved"):
        return {"decision": "PENDING_APPROVAL", "reason": "human approval required", "audit_id": audit(decision="PENDING_APPROVAL", user=sub, tool=tool)}
    if tool == "sis.status":
        rec = SIS.get(target, {})
        return {"decision": "ALLOW", "status": rec, "audit_id": audit(decision="ALLOW", user=sub, tool=tool, target=target, result=mask(json.dumps(rec)))}
    sc = scorecard(q) if q else {}
    prompt = "Answer briefly and factually for a student or family. Question: " + q + " Context (College Scorecard): " + json.dumps(sc)[:500]
    kw = {"modelId": M, "body": json.dumps({"anthropic_version": "bedrock-2023-05-31", "max_tokens": 150, "messages": [{"role": "user", "content": prompt}]})}
    if G:
        kw["guardrailIdentifier"] = G; kw["guardrailVersion"] = "DRAFT"
    r = json.loads(br.invoke_model(**kw)["body"].read())
    ans = (r.get("content") or [{}])[0].get("text", "")
    return {"decision": "ALLOW", "answer": mask(ans), "scorecard": sc, "source": "collegescorecard",
            "audit_id": audit(decision="ALLOW", user=sub, tool=tool, query=mask(q), answer=mask(ans), source="collegescorecard")}
